import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";

const TAB_LIST = ["Upcoming", "Outstanding", "Transactions"];

export default function Money() {
  const [tab, setTab] = useState(0);
  const [upcoming, setUpcoming] = useState([]);
  const [outstanding, setOutstanding] = useState([]);
  const [transactions, setTransactions] = useState([]);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState("");
  const token = localStorage.getItem("token");
  const navigate = useNavigate();

  useEffect(() => {
    setLoading(true);
    setError("");
    let url = "";
    if (tab === 0) url = "/api/money/upcoming";
    else if (tab === 1) url = "/api/money/outstanding";
    else if (tab === 2) url = "/api/money/transactions";

    fetch(`http://localhost:5000${url}`, {
      headers: { Authorization: `Bearer ${token}` },
    })
      .then((res) => res.json())
      .then((data) => {
        if (tab === 0)
          setUpcoming(Array.isArray(data.accounts) ? data.accounts : []);
        else if (tab === 1)
          setOutstanding(Array.isArray(data.accounts) ? data.accounts : []);
        else if (tab === 2)
          setTransactions(
            Array.isArray(data.transactions) ? data.transactions : []
          );
        setError("");
      })
      .catch(() => setError("Failed to load data"))
      .finally(() => setLoading(false));
  }, [tab, token]);

  function renderAccountCard(acc) {
    return (
      <div
        key={acc._id}
        style={{
          display: "flex",
          alignItems: "center",
          borderRadius: 20,
          background: "#fff",
          padding: "10px 14px",
          marginBottom: 15,
          position: "relative",
          boxShadow: "0 1px 8px #e9eafe40",
        }}
      >
        <img
          src={
            acc.profilePic || "https://randomuser.me/api/portraits/men/1.jpg"
          }
          alt={acc.name}
          style={{
            width: 48,
            height: 48,
            borderRadius: "50%",
            objectFit: "cover",
            marginRight: 15,
          }}
        />
        <div style={{ flex: 1 }}>
          <div style={{ fontWeight: 700, fontSize: 16, color: "#232743" }}>
            {acc.name}
          </div>
          <div style={{ fontWeight: 400, fontSize: 13, color: "#8d93b8" }}>
            {acc.dueDateLabel}
          </div>
        </div>
        <div style={{ textAlign: "right" }}>
          <div style={{ color: "#E84D4F", fontWeight: 700, fontSize: 17 }}>
            {acc.statusText}
            {acc.statusText && acc.statusAmount !== undefined && (
              <span>: ₹{Number(acc.statusAmount).toLocaleString()}</span>
            )}
          </div>
        </div>
        <span
          style={{
            cursor: "pointer",
            position: "absolute",
            right: 13,
            top: 10,
            color: "#b7bbda",
            fontSize: 22,
            fontWeight: 900,
          }}
        >
          ...
        </span>
      </div>
    );
  }

  function renderTransactionCard(txn) {
    return (
      <div
        key={txn._id}
        style={{
          display: "flex",
          alignItems: "center",
          borderRadius: 14,
          background: "#fff",
          padding: "9px 13px",
          marginBottom: 12,
          boxShadow: "0 1px 7px #e9eafe30",
        }}
      >
        <div style={{ flex: 2 }}>
          <div
            style={{
              color: txn.status === "Paid" ? "#5da86c" : "#E84D4F",
              fontWeight: 600,
              fontSize: 14,
            }}
          >
            {txn.status === "Paid" ? "Paid to" : "To Pay"}
          </div>
          <div style={{ fontWeight: 600, color: "#333" }}>{txn.name}</div>
        </div>
        <div style={{ flex: 2, textAlign: "center" }}>
          <div>Interest {Number(txn.interest).toLocaleString()}</div>
          <div style={{ fontSize: 13, color: "#999" }}>{txn.dateLabel}</div>
        </div>
        <div style={{ flex: 1, textAlign: "right" }}>
          <span
            style={{ color: "#5271ff", fontWeight: 600, cursor: "pointer" }}
          >
            Edit
          </span>
        </div>
      </div>
    );
  }

  return (
    <div
      style={{ minHeight: "100vh", background: "#edf0fd", paddingBottom: 80 }}
    >
      <div
        style={{
          position: "sticky",
          top: 0,
          zIndex: 10,
          background: "#edf0fd",
          padding: "0 0 10px 0",
        }}
      >
        <h2
          style={{
            padding: "16px 16px 0 16px",
            margin: 0,
            fontWeight: 700,
            color: "#393f61",
            fontSize: 23,
          }}
        >
          Money
        </h2>
        <div
          style={{
            display: "flex",
            background: "#e0e4f8",
            borderRadius: 16,
            margin: "16px 12px 0 12px",
          }}
        >
          {TAB_LIST.map((t, i) => (
            <button
              key={t}
              onClick={() => setTab(i)}
              style={{
                flex: 1,
                background: tab === i ? "#fff" : "#e0e4f8",
                color: tab === i ? "#5271ff" : "#232743",
                fontWeight: 600,
                border: "none",
                fontSize: 15,
                borderRadius: 16,
                padding: "11px 0",
                cursor: "pointer",
              }}
            >
              {t}
            </button>
          ))}
        </div>
      </div>
      <div style={{ padding: "20px 14px 60px 14px" }}>
        {loading ? (
          <div>Loading...</div>
        ) : error ? (
          <div style={{ color: "red" }}>{error}</div>
        ) : tab === 0 ? (
          upcoming.length ? (
            upcoming.map(renderAccountCard)
          ) : (
            <p style={{ textAlign: "center", color: "#a0a5cf" }}>
              No upcoming payments.
            </p>
          )
        ) : tab === 1 ? (
          outstanding.length ? (
            outstanding.map(renderAccountCard)
          ) : (
            <p style={{ textAlign: "center", color: "#a0a5cf" }}>
              No outstanding payments.
            </p>
          )
        ) : transactions.length ? (
          <>
            <div style={{ marginBottom: 6, textAlign: "right" }}>
              <button
                style={{
                  background: "none",
                  border: "none",
                  color: "#5271ff",
                  fontWeight: 600,
                  fontSize: 14,
                  cursor: "pointer",
                }}
              >
                Download statement
              </button>
            </div>
            {transactions.map(renderTransactionCard)}
          </>
        ) : (
          <p style={{ textAlign: "center", color: "#a0a5cf" }}>
            No transactions.
          </p>
        )}
      </div>
      {/* Bottom nav bar: use your existing nav component here if needed */}
      <div
        style={{
          position: "fixed",
          left: 0,
          right: 0,
          bottom: 0,
          zIndex: 20,
          background: "transparent",
        }}
      >
        <div style={{ maxWidth: 430, margin: "auto" }}>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              background: "#879cf4",
              borderRadius: 40,
              padding: 6,
              margin: 7,
              boxShadow: "0 1px 8px #5271ff28",
            }}
          >
            <button
              style={{
                flex: 1,
                background: "transparent",
                border: "none",
                color: "#fff",
                fontWeight: 500,
                fontSize: 18,
                display: "flex",
                alignItems: "center",
                gap: 8,
